ber&#34;&gt;185&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;114&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;172&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;114&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;167&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;112&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;161&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;109&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;165&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;107&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;170&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;99&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;171&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;97&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;167&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;89&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;164&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;81&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;162&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;77&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;155&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;81&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;148&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;87&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;140&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;96&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;138&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;105&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;141&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;110&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;136&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;111&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;126&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;113&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;129&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;118&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;117&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;114&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;137&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;115&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;146&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;114&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;155&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;115&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;158&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;121&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;157&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;156&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;134&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;157&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;136&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;156&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;136&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pts1 = np.array(first, np.int32)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pts1 = pts1.reshape((-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pts2 = np.array(second, np.int32)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pts2 = pts2.reshape((-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.polylines(img,[pts1, pts2],&lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;,(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;255&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;255&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.imshow(&lt;span class=&#34;string&#34;&gt;&amp;quot;img&amp;quot;&lt;/span&gt;, img)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.waitKey(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;事实证明，网页原图片是用不到的，直接生成一个纯色图片就可以&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;img = np.zeros((&lt;span class=&#34;number&#34;&gt;512&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;512&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;), np.uint8)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到结果&lt;/p&gt;
&lt;img src=&#34;https://s2.loli.net/2022/03/31/up6kroOIvtNdMiE.png&#34; alt=&#34;level9&#34; width=&#34;300px&#34;&gt;

&lt;p&gt;那么是cow&amp;#x2F;bull&amp;#x2F;ox&amp;#x2F;cattle，尝试几次就知道了&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-10&#34;&gt;Level 10&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;发现图片牛身体部分带有链接，点击发现一个未收尾的list，&lt;code&gt;a = [1, 11, 21, 1211, 111221,&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;没有系统刷过算法的我一时间没有看懂这是什么排列，搜索&lt;code&gt;1, 11, 21, 1211, 111221&lt;/code&gt;后发现，原来这叫做&lt;a href=&#34;https://en.wikipedia.org/wiki/Look-and-say_sequence&#34;&gt;Look-and-say sequence&lt;/a&gt;。好嘛知道这是什么东西了就好弄了，上手&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;a = [&lt;span class=&#34;string&#34;&gt;&amp;#x27;1&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c1, c2 = &lt;span class=&#34;string&#34;&gt;&amp;#x27;1&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; _ &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;30&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    count, i, j = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; i &amp;lt; &lt;span class=&#34;built_in&#34;&gt;len&lt;/span&gt;(c1):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; j &amp;lt; &lt;span class=&#34;built_in&#34;&gt;len&lt;/span&gt;(c1):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; c1[i] == c1[j]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                count += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                j += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        c2 += &lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(count) + c1[i]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        i = j&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        count = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    a.append(c2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    c1 = c2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    c2 = &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;len&lt;/span&gt;(a[&lt;span class=&#34;number&#34;&gt;30&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到下一题地址&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-11&#34;&gt;Level 11&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;odd even，奇偶数，只有一张图片，那么自然还是要进行图片处理&lt;/p&gt;
&lt;p&gt;对两坐标数值之和进行奇偶分类，分离图像&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; cv2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img = cv2.imread(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/cave.jpg&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x, y, _ = img.shape&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img1, img2 = np.zeros((x//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,y//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;), np.uint8), np.zeros((x//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,y//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;), np.uint8)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(x):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; j &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(y):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (i+j)%&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            img1[i//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;][j//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;] = img[i][j]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            img2[i//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;][j//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;] = img[i][j]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.imshow(&lt;span class=&#34;string&#34;&gt;&amp;quot;odd&amp;quot;&lt;/span&gt;, img1)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.imshow(&lt;span class=&#34;string&#34;&gt;&amp;quot;even&amp;quot;&lt;/span&gt;, img2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.waitKey(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到&lt;code&gt;&amp;quot;even&amp;quot;&lt;/code&gt;图像右上角的文字即为下一题地址&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-12&#34;&gt;Level 12&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;dealing evil，有点摸不到头脑&lt;/p&gt;
&lt;p&gt;图片源地址为&lt;code&gt;evil1.jpg&lt;/code&gt;，会有evil2，evil3，甚至evil4，evil5吗，试试。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;evil2.jpg&lt;/code&gt;显示&lt;code&gt;not jpg, _.gfx&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;.gfx是什么意思呢，google一下&lt;br&gt;The GFX file type is primarily associated with Cue Club Image File. -&amp;gt;&lt;a href=&#34;https://filext.com/file-extension/GFX&#34;&gt;source&lt;/a&gt;&lt;br&gt;可以理解为是个图片类的扩展名，把&lt;code&gt;evil2.jpg&lt;/code&gt;改为&lt;code&gt;evil2.gfx&lt;/code&gt;果然是个文件链接。&lt;/p&gt;
&lt;p&gt;再试试&lt;code&gt;evil3.jpg&lt;/code&gt;，OK，显示&lt;code&gt;no more evils&lt;/code&gt;了，那应该信息在&lt;code&gt;evil2.gfx&lt;/code&gt;和&lt;code&gt;evil1.jpg&lt;/code&gt;这两个文件当中了（还是需要继续尝试的，下一题需要）&lt;/p&gt;
&lt;p&gt;打开&lt;code&gt;evil2.gfx&lt;/code&gt;，尝试直接转为&lt;code&gt;evil2.jpg&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/evil2.gfx&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;rb&amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    text = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/evil2.jpg&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;wb&amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    f.write(text)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;emm，打不开&lt;/p&gt;
&lt;p&gt;众所周知dealing有发牌的意思，尝试如果把&lt;code&gt;evil2.gfx&lt;/code&gt;中的信息逐字节分别注入到若干个文件中打开&lt;/p&gt;
&lt;p&gt;从分为2个文件，一路尝试到分为5个文件，终于出现了能够读取的图像，连在一起即为下一题地址&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/evil2.gfx&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;rb&amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    text = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;#x27;assets/&lt;span class=&#34;subst&#34;&gt;&amp;#123;i&amp;#125;&lt;/span&gt;.jpg&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        f.write(text[i::&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;wait，那么&lt;code&gt;evil1.jpg&lt;/code&gt;的作用是什么？找来找去看到图中发的牌都为&lt;code&gt;5&lt;/code&gt;，大概是个线索吧，虽然被我忽略了...&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-13&#34;&gt;Level 13&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;按键5处有链接，得到一个xml文件。&lt;/p&gt;
&lt;p&gt;说实话，这题我是从网上找的解析，触及我盲区了。这里补充一些自己的理解&lt;/p&gt;
&lt;p&gt;xml-rpc就是一个post请求，形式为xml格式，执行结果也会以xml格式返回。python中执行这类操作有内置模块&lt;code&gt;xmlrpc.client&lt;/code&gt;和&lt;code&gt;xmlrpc.server&lt;/code&gt;，二者作用一目了然，这一题要用到的即为&lt;code&gt;xmlrpc.client&lt;/code&gt;模块&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; xmlrpc.client&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;post = xmlrpc.client.ServerProxy(&lt;span class=&#34;string&#34;&gt;&amp;quot;http://www.pythonchallenge.com/pc/phonebook.php)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;构建好&lt;code&gt;ServerProxy&lt;/code&gt;对象后利用&lt;a href=&#34;https://docs.python.org/3/library/xmlrpc.client.html#xmlrpc.client.ServerProxy.system.listMethods&#34;&gt;system.listMethods&lt;/a&gt;方法查询服务端提供的method&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(post.system.listMethods())&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;[&amp;#39;phone&amp;#39;, &amp;#39;system.listMethods&amp;#39;, &amp;#39;system.methodHelp&amp;#39;, &amp;#39;system.methodSignature&amp;#39;, &amp;#39;system.multicall&amp;#39;, &amp;#39;system.getCapabilities&amp;#39;]&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;其中&lt;code&gt;phone&lt;/code&gt;看起来是这个服务端特有的一个method方法，用&lt;code&gt;system.methodHelp&lt;/code&gt;查询该method的作用&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(post.system.methodHelp(&lt;span class=&#34;string&#34;&gt;&amp;quot;phone&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;Returns the phone of a person&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;OK，需要的method也知道了，现在还缺少的条件就是&lt;code&gt;person&lt;/code&gt;了。在网上查了一下才看见，原来上一题的&lt;code&gt;evil4.jpg&lt;/code&gt;是有信息的，怪我太单纯，相信了它的鬼话。但是只有ie浏览器能够访问，或者利用&lt;code&gt;curl&lt;/code&gt;语句获取，即为此题&lt;code&gt;person&lt;/code&gt;的名字&amp;quot;Bert&amp;quot;&lt;/p&gt;
&lt;p&gt;查询结果为&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;555-ITALY&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2&gt;&lt;span id=&#34;level-14&#34;&gt;Level 14&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;结合walk around以及上方图片，应该与绕圈圈或者螺旋有关。下面的条形码(?)图片应该就是要处理的图片了。网页源码中带有注释&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;remember: 100*100 &amp;#x3D; (100+99+99+98) + (...&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;而且注意到wire.png在浏览器DevTools中的信息：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;Rendered size:100 × 100 px&lt;br&gt;Rendered aspect ratio:1∶1&lt;br&gt;Intrinsic size:10000 × 1 px&lt;br&gt;Intrinsic aspect ratio:10000∶1&lt;br&gt;File size:15.9 kB&lt;br&gt;Current source:&lt;a href=&#34;http://www.pythonchallenge.com/pc/return/wire.png&#34;&gt;http://www.pythonchallenge.com/pc/return/wire.png&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;它并不是100px*100px的图片，而是10000px*1px的图片&lt;/p&gt;
&lt;p&gt;那么这个等式代表什么呢？&lt;/p&gt;
&lt;p&gt;举个简单的例子，一张5px*5px的图片，从最外侧沿直线一圈一圈螺旋状向内绕，如下图沿同颜色的色块走到边界然后转弯&lt;/p&gt;
&lt;img src=&#34;https://s2.loli.net/2022/04/01/hpOasHD6YtiycQK.png&#34; width=&#34;300px&#34; alt=&#34;spiral&#34;&gt;

&lt;p&gt;那么以每次转弯为边界，每次走过的像素数依次是5,4,4,3,3,2,2,1,1&lt;/p&gt;
&lt;p&gt;拓展到100px*100px的图片，那么上面的等式就能补全了&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;100*100 &amp;#x3D; 100+99+99+98+98+97+97+...+3+3+2+2+1+1&lt;br&gt;&amp;#x3D;（100+99+99+98)+(98+97+97+96)+...+(5+4+4+3)+(3+2+2+1)+1&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;那么要对&lt;code&gt;wire.png&lt;/code&gt;进行的处理即为螺旋式将10000个像素逐个填入到100px*100px的图像当中咯&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; cv2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img = cv2.imread(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/wire.png&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img1 = np.zeros((&lt;span class=&#34;number&#34;&gt;300&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;300&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;), np.uint8)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img1.fill(&lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dirs = [(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;), (&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;), (&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;), (-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;count, i, pos_x, pos_y = &lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, -&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dis = count//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; dis &amp;gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;dir&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; dirs:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dis = count//&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; _ &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(dis):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            pos_x = pos_x + &lt;span class=&#34;built_in&#34;&gt;dir&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            pos_y = pos_y + &lt;span class=&#34;built_in&#34;&gt;dir&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            img1[pos_x, pos_y] = img[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;, i]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            i += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        count -= &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.imshow(&lt;span class=&#34;string&#34;&gt;&amp;quot;result&amp;quot;&lt;/span&gt;, img1)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cv2.waitKey(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;voila~，诶他叫uzi，替换地址就是下一题了&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-15&#34;&gt;Level 15&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;首先直接上结论，著名音乐家Mozart&lt;/p&gt;
&lt;p&gt;为什么呢？注释里说&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;todo: buy flowers for tomorrow&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;然后我就去查了1月27日出生的名人，so，第一个就是WOLFGANG AMADEUS MOZART，然后就进入下一题了.....&lt;/p&gt;
&lt;p&gt;OK，回过头分析一下这道题，针对结果给出过程了属于是&lt;/p&gt;
&lt;p&gt;首先1月27日肯定是个大日子没错了，注意图片右下角中的下月预览，共29天，那么这一年(1XX6年)是个闰年，而且当年1月1日为周四。再结合&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;he ain&amp;#39;t the youngest, he is the second&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;也就是求从当今向前推，第二个最后一位数为6的闰年咯，虽然已经知道答案是1756了，但当然还是要做一下&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; calendar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;front, count = &lt;span class=&#34;number&#34;&gt;2020&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    year = front + &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; calendar.isleap(year) &lt;span class=&#34;keyword&#34;&gt;and&lt;/span&gt; calendar.weekday(year, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) == &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        count += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    front -= &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; count == &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(year)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2&gt;&lt;span id=&#34;level-16&#34;&gt;Level 16&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Let me get this straight&lt;/p&gt;
&lt;p&gt;看上去应该是把这些粉&amp;#x2F;紫色的色块对齐？大概看了一下，前面四行像素中都只有一个粉&amp;#x2F;紫色块，那应该就是这样了。用截图工具逐像素查一下，发现这些粉&amp;#x2F;紫色块长度都为5个像素，那么接下来就容易了。&lt;/p&gt;
&lt;p&gt;opencv无法处理&lt;code&gt;.gif&lt;/code&gt;文件，所以花了点时间简单学习了下pillow的使用&lt;/p&gt;
&lt;p&gt;首先要确定每行中粉&amp;#x2F;紫色块的位置(即其所在像素在整个像素行list中的索引值)，只需在一行像素中找到连续5个值完全相同的像素即可。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; PIL &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; Image&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img = Image.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/mozart.gif&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pixels = [img.getpixel((pos_x, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; pos_x &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(img.size[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;])]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;flag = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;len&lt;/span&gt;(pixels)-&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; j &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; pixels[i] == pixels[i+j]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            flag = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            flag = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; flag == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(pixels[i])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;195&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;那么需要找的像素值就应该是&lt;code&gt;195&lt;/code&gt;了。找到这个像素后将此像素之前的部分全部切下接到整行像素的末尾试一下&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; PIL &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; Image&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img = Image.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/mozart.gif&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; pos_y &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(img.size[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    pixels = [img.getpixel((pos_x, pos_y)) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; pos_x &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(img.size[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;])]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    flag = pixels.index(&lt;span class=&#34;number&#34;&gt;195&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    pixels = pixels[flag:] + pixels[:flag]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; pos_x &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(img.size[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        img.putpixel((pos_x,pos_y), pixels[pos_x])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img.show()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;芝麻芝麻~&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-17&#34;&gt;Level 17&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;诶，主图左下角的部分好像见过，是第四题的图，那么，又是一道网页请求类的题目？&lt;/p&gt;
&lt;p&gt;查看网页cookies&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;you%20should%20have%20followed%20busynothing...&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;看样子应该是把第四题的首个地址改为&lt;code&gt;...?busynothing=12345&lt;/code&gt;然后进行网页请求咯&lt;/p&gt;
&lt;p&gt;然而并不是，除了一句&lt;code&gt;that&amp;#39;s it&lt;/code&gt;什么也没得到，猜测这可能是循环请求结束的节点。或许是要读取cookie内容？&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; re&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; requests&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url=&lt;span class=&#34;string&#34;&gt;&amp;#x27;http://www.pythonchallenge.com/pc/def/linkedlist.php?busynothing=12345&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r=requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;txt=r.text&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cookies = r.cookies[&lt;span class=&#34;string&#34;&gt;&amp;#x27;info&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url=&lt;span class=&#34;string&#34;&gt;&amp;#x27;http://www.pythonchallenge.com/pc/def/linkedlist.php?busynothing=&amp;#x27;&lt;/span&gt;+txt.split()[-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    r=requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    txt = r.text&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(txt)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    cookies += r.cookies[&lt;span class=&#34;string&#34;&gt;&amp;#x27;info&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    result = re.search(&lt;span class=&#34;string&#34;&gt;&amp;#x27;the next busynothing is (\d+)&amp;#x27;&lt;/span&gt;, txt)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; result == &lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(cookies)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;BZh91AY%26SY%94%3A%E2I%00%00%21%19%80P%81%11%00%AFg%9E%A0%20%00hE%3DM%B5%23%D0%D4%D1%E2%8D%06%A9%FA%26S%D4%D3%21%A1%EAi7h%9B%9A%2B%BF%60%22%C5WX%E1%ADL%80%E8V%3C%C6%A8%DBH%2632%18%A8x%01%08%21%8DS%0B%C8%AF%96KO%CA2%B0%F1%BD%1Du%A0%86%05%92s%B0%92%C4Bc%F1w%24S%85%09%09C%AE%24%90&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;emm，看开头像是之前做过的&lt;a href=&#34;#level-8&#34;&gt;bzip2压缩&lt;/a&gt;，但是编码有问题。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;line = urllib.parse.unquote_to_bytes(cookies)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(line)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到结果&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;b&amp;#39;BZh91AY&amp;amp;SY\x94:\xe2I\x00\x00!\x19\x80P\x81\x11\x00\xafg\x9e\xa0 \x00hE&amp;#x3D;M\xb5#\xd0\xd4\xd1\xe2\x8d\x06\xa9\xfa&amp;amp;S\xd4\xd3!\xa1\xeai7h\x9b\x9a+\xbf&amp;#96;&amp;quot;\xc5WX\xe1\xadL\x80\xe8V&amp;lt;\xc6\xa8\xdbH&amp;amp;32\x18\xa8x\x01\x08!\x8dS\x0b\xc8\xaf\x96KO\xca2\xb0\xf1\xbd\x1du\xa0\x86\x05\x92s\xb0\x92\xc4Bc\xf1w$S\x85\t\tC\xae$\x90&amp;#39;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;这回看上去和bzip压缩后的结果很像了，解压&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(bz2.decompress(line).decode(&lt;span class=&#34;string&#34;&gt;&amp;quot;utf-8&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;is it the 26th already? call his father and inform him that &amp;quot;the flowers are on their way&amp;quot;. he&amp;#39;ll understand.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;code&gt;call his father&lt;/code&gt;，结合&lt;code&gt;26th&lt;/code&gt;，那么应该是Mozart的父亲咯，在网上查了一下名叫&lt;code&gt;Leopold&lt;/code&gt;，&lt;code&gt;call&lt;/code&gt;自然是&lt;a href=&#34;#level-13&#34;&gt;13题&lt;/a&gt;中的&lt;code&gt;phone&lt;/code&gt;方法&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; xmlrpc.client&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;post = xmlrpc.client.ServerProxy(&lt;span class=&#34;string&#34;&gt;&amp;quot;http://www.pythonchallenge.com/pc/phonebook.php&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(post.phone(&lt;span class=&#34;string&#34;&gt;&amp;quot;Leopold&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;555-VIOLIN&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;替换&lt;code&gt;.../violin.html&lt;/code&gt;试试&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;no! i mean yes! but ..&amp;#x2F;stuff&amp;#x2F;violin.php.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;继续修改网址。emm，网页题目叫&lt;code&gt;it&amp;#39;s me. What do you want?&lt;/code&gt;，内容是Leopold Mozart的画像。要做什么就很明了了&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; requests&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url = &lt;span class=&#34;string&#34;&gt;&amp;#x27;http://www.pythonchallenge.com/pc/stuff/violin.php&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;headers = &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;#x27;Cookie&amp;#x27;&lt;/span&gt;:&lt;span class=&#34;string&#34;&gt;&amp;#x27;info=the flowers are on their way&amp;#x27;&lt;/span&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r = requests.get(url, headers=headers)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(r.text)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到结果&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;it&amp;#x27;s me. what do you want?&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;link&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;stylesheet&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text/css&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;../style.css&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;center&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;font&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;color&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;gold&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;img&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;leopold.jpg&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;border&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;0&amp;quot;&lt;/span&gt;/&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;oh well, don&amp;#x27;t you dare to forget the balloons.&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;font&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;替换为balloons即得到下一题地址了，哦对了，是在第17题题目的地址上替换，不是在Leopold画像的网页地址上替换&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-18&#34;&gt;Level 18&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Can you tell the difference?&lt;/p&gt;
&lt;p&gt;两张图片，亮度略有差别。源码中带有注释&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;it is more obvious that what you might think&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;那既然这么说，就试试luminance&amp;#x2F;brightness咯。&lt;code&gt;brightness.html&lt;/code&gt;页面没有区别，注释中内容变为了&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;maybe consider deltas.gz&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;替换地址，得到&lt;code&gt;deltas.gz&lt;/code&gt;文件。处理&lt;code&gt;.gz&lt;/code&gt;文件要用的应该就是&lt;a href=&#34;https://docs.python.org/3/library/gzip.html#module-gzip&#34;&gt;gzip模块&lt;/a&gt;了&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; gzip&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; gzip.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/deltas.gz&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;rb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    content = f.read().decode()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(content)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到的结果很有意思，分为了两栏，但行数有所差别，或许要比较的是这两栏的区别？那么要用的就是&lt;a href=&#34;https://docs.python.org/3/library/difflib.html#module-difflib&#34;&gt;difflib模块&lt;/a&gt;咯，去学习一下&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; gzip, difflib&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file1, file2 = [], []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; gzip.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/deltas.gz&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;rb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    content = f.readline().decode()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; content:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        file1.append(content[:&lt;span class=&#34;number&#34;&gt;53&lt;/span&gt;]+&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        file2.append(content[&lt;span class=&#34;number&#34;&gt;56&lt;/span&gt;:])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        content = f.readline().decode()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;diff = difflib.Differ().compare(file1, file2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l1, l2, common = [], [], []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; line &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; diff:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; line[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;] == &lt;span class=&#34;string&#34;&gt;&amp;#x27;-&amp;#x27;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        l1.append(line[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;elif&lt;/span&gt; line[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;] == &lt;span class=&#34;string&#34;&gt;&amp;#x27;+&amp;#x27;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        l2.append(line[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        common.append(line[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;l1: &lt;span class=&#34;subst&#34;&gt;&amp;#123;l1&amp;#125;&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;l2: &lt;span class=&#34;subst&#34;&gt;&amp;#123;l2&amp;#125;&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;common: &lt;span class=&#34;subst&#34;&gt;&amp;#123;common&amp;#125;&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到结果&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;l1: [&amp;#39;89 50 4e 47 0d 0a 1a 0a ...]&lt;br&gt;l2: [&amp;#39;89 50 4e 47 0d 0a 1a 0a ...]&lt;br&gt;common: [&amp;#39;89 50 4e 47 0d 0a 1a 0a ...]&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;熟悉png文件结构的话已经看出比对出的三个结果应该怎么处理了。&lt;/p&gt;
&lt;p&gt;三个结果起始的八个字节正是png文件的文件头(signature)-&amp;gt;&lt;a href=&#34;https://en.wikipedia.org/wiki/Portable_Network_Graphics#File_header&#34;&gt;source&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;下面将三个结果分别存储为png文件，即得到下一题的地址、账号与密码。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/lvl18_1.png&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f1:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; line &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; l1:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        f1.write(&lt;span class=&#34;built_in&#34;&gt;bytes&lt;/span&gt;([&lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;(o, &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; o &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; line.split(&lt;span class=&#34;string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; o]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/lvl18_2.png&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f2:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; line &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; l2:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        f2.write(&lt;span class=&#34;built_in&#34;&gt;bytes&lt;/span&gt;([&lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;(o, &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; o &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; line.split(&lt;span class=&#34;string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; o]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/lvl18_3.png&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f3:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; line &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; common:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        f3.write(&lt;span class=&#34;built_in&#34;&gt;bytes&lt;/span&gt;([&lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;(o, &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; o &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; line.split(&lt;span class=&#34;string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; o]))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2&gt;&lt;span id=&#34;level-19&#34;&gt;Level 19&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;一张印度地图，以及网页注释中的一封邮件&lt;/p&gt;
&lt;p&gt;看样子是要处理音频？而且说明了用base64进行编码，要用的自然就是&lt;code&gt;base64.b64decode()&lt;/code&gt;了&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; base64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/txt_for_19.txt&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;r&amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    content = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;audio = base64.b64decode(content)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;assets/indian.wav&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    f.write(audio)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到音频为&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;Sorry!&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;改地址试一下&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;&amp;quot;what are you apologizing for?&amp;quot;&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;看上去不对，有被忽略的线索。&lt;/p&gt;
&lt;p&gt;对音频信息不是很了解，正好借刚刚的&lt;code&gt;indian.wav&lt;/code&gt;这个文件学习一下&lt;code&gt;wave&lt;/code&gt;模块和相关的参数含义&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; wave&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; wave.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/indian.wav&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;rb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; sound:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    params = sound.getparams()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(params)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;_wave_params(nchannels&amp;#x3D;1, sampwidth&amp;#x3D;2, framerate&amp;#x3D;11025, nframes&amp;#x3D;55788, comptype&amp;#x3D;&amp;#39;NONE&amp;#39;, compname&amp;#x3D;&amp;#39;not compressed&amp;#39;)&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;大概是：单声道，采样率2byte，帧率11025hz，共55788帧，无压缩&lt;/p&gt;
&lt;p&gt;注意到图片中陆地颜色和海洋颜色相反，&lt;code&gt;reverse&lt;/code&gt;？尝试将音频整体翻转&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; wave&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; wave.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/indian.wav&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;rb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; sound:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    params = sound.getparams()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    content = sound.readframes(sound.getnframes())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; wave.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/results.wav&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; output:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    output.setparams(params=params)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    output.writeframes(content[::-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;得到的结果什么也听不出来，不对。尝试逐帧反转&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; wave&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; wave.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/indian.wav&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;rb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; sound:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; wave.&lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;assets/results.wav&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; output:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        output.setparams(sound.getparams())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(sound.getnframes()):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            frame = sound.readframes(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            output.writeframes(frame[::-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;&amp;quot;you are an idiot~ ah, ah, ah, ah ...&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;虽然，但是，有被冒犯到...&lt;/p&gt;
&lt;p&gt;替换网址，即得到进入下一题的链接&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;level-20&#34;&gt;Level 20&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;暂时没头绪……&lt;/p&gt;

 &lt;h2&gt;&lt;span id=&#34;ying-jian&#34;&gt;硬件&lt;/span&gt;&lt;/h2&gt;&lt;ul&gt;
&lt;li&gt;&lt;del&gt;废旧&lt;/del&gt;路由NEWIFI-MINI，买了好多年了，家里就这一个带U口的路由，折腾折腾试试看&lt;/li&gt;
&lt;li&gt;已格式化为ext4的U盘，格式化方法众多&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2&gt;&lt;span id=&#34;guo-cheng&#34;&gt;过程&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;USB应用程序-&amp;gt;允许运行Optware-&amp;gt;Entware&lt;/li&gt;
&lt;li&gt;配置扩展环境-&amp;gt;opt强制安装-&amp;gt;安装到U盘&lt;ul&gt;
&lt;li&gt;如果设置好之后ssh连接到路由器输入命令&lt;code&gt;df -h&lt;/code&gt;后&amp;#x2F;opt仍未挂载到U盘中，可通过命令&lt;code&gt;mount \dev\sda1 \opt&lt;/code&gt;手动挂载。其中&lt;code&gt;\dev\sda1&lt;/code&gt;是我的U盘，根据实际情况填入对应的路径即可。&lt;br&gt; 安装opt耗时较长，和网络环境及硬件水平有关，耐心等待log栏中完成的信息。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;建立swap分区&lt;ul&gt;
&lt;li&gt;&lt;p&gt;NEWIFI-MINI内存只有64MB，跑不动mysql这种服务。&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;dd if=/dev/zero of=/opt/swap bs=1M count=1024 #分大了点，反正U盘够大&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mkswap /opt/swap&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;swapon /opt/swap&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;建立好swap分区后如果LNMP不停重启，不妨试试重启路由器&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;路由器重启后swap分区不会自动挂载，在启动后运行的脚本中加入&lt;code&gt;swapon /opt/swap&lt;/code&gt;以开机自动挂载swap分区&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;搭建web环境-&amp;gt;启用nginx+mysql+php环境&lt;ul&gt;
&lt;li&gt;&lt;p&gt;遇到了两个问题：找不到nginx、找不到mysqld，解决办法很简单，ssh客户端中输入命令&lt;/p&gt;
  &lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;opkg update&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;opkg install nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;opkg install mysql-server&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;即可正常下载安装LNMP&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt; 这一步耗时也较长，仍需耐心等待log栏中完成的信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;phpmyadmin下载失败，长时间卡在下载进程，可从官网手动下载4.8.3版本（看log栏中显示的链接信息，可能版本会有所不同），压缩包名称修改为&lt;code&gt;phpmyadmin.zip&lt;/code&gt;后传入路由器&lt;code&gt;\opt\wwwroot&lt;/code&gt;路径即可正常解压运行&lt;/li&gt;
&lt;li&gt;一切准备好后路由器log栏中发现mysql仍不停重启，ssh终端运行mysql后发现缺少mysql库，大概是本地数据库初始化未完成的原因，找到&lt;code&gt;mysql&lt;/code&gt;下的&lt;code&gt;bin&lt;/code&gt;目录，（padavan系统为&lt;code&gt;/opt/bin&lt;/code&gt;目录）运行&lt;code&gt;mysql_install_db&lt;/code&gt;，重新初始化mysql库后恢复正常&lt;/li&gt;
&lt;li&gt;几次运行后发现有时phpmyadmin无法进入，试了试把phpmyadmin config中的&lt;code&gt;$cfg[&amp;#39;Servers&amp;#39;][$i][&amp;#39;host&amp;#39;] = &amp;#39;localhost&amp;#39;;&lt;/code&gt;更改为&lt;code&gt;$cfg[&amp;#39;Servers&amp;#39;][$i][&amp;#39;host&amp;#39;] = &amp;#39;127.0.0.1&amp;#39;;&lt;/code&gt;后运行正常。&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;hou-ji&#34;&gt;后记&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;使用效果&lt;br&gt;&lt;img src=&#34;https://s2.loli.net/2022/03/11/AfRPeDobru9Tz6B.gif&#34; alt=&#34;web view&#34;&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;gif录制压缩原因，图片失真严重，实际查看时图片分辨率保持图片源分辨率&lt;br&gt;&lt;em&gt;此篇只做记录用，以方便再折腾其他功能&lt;/em&gt;&lt;/p&gt;
&lt;/blockquote&gt;

 &lt;p&gt;昨天把手里的8T刷了&lt;a href=&#34;https://download.pixelexperience.org/&#34;&gt;Pixel Experience&lt;/a&gt;，简单记录一下遇到的几个问题。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2&gt;&lt;span id=&#34;shua-ru-pixel-experience&#34;&gt;刷入pixel experience&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;&lt;a href=&#34;https://wiki.pixelexperience.org/devices/kebab/install&#34;&gt;Pixel Experience官方的刷机教程&lt;/a&gt;已经比较详尽了，直接按照步骤一步步操作即可。&lt;/p&gt;
&lt;p&gt;以下开始记录遇到的问题，其实解决方案网上搜一搜也有很多，这里记下我所用的有效的方案留个底以备用吧&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;p&gt;进行到第四步时，执行&lt;code&gt;fastboot devices&lt;/code&gt;查询不到设备。&lt;/p&gt;
&lt;p&gt; 首先原因为驱动未安装，在设备管理器中&lt;code&gt;右键Android&lt;/code&gt;，依次选择&lt;code&gt;更新驱动程序软件&lt;/code&gt;、&lt;code&gt;浏览计算机以查找驱动程序软件&lt;/code&gt;、&lt;code&gt;从计算机的设备驱动程序列表中选择&lt;/code&gt;、&lt;code&gt;Android Phone&lt;/code&gt;、&lt;code&gt;Android Bootloader Interface&lt;/code&gt;，安装好驱动，再次执行&lt;code&gt;fastboot devices&lt;/code&gt;时就可以顺利找到设备了。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;教程&lt;a href=&#34;https://wiki.pixelexperience.org/devices/kebab/install/#pre-install-instructions&#34;&gt;pre-install instructions&lt;/a&gt;部分提到&lt;code&gt;copy-partitions-20210323_1922.zip&lt;/code&gt;文件无法下载&lt;/p&gt;
&lt;p&gt; 原文件所在repo中没有找到这个文件，可能是后来更改时弄错了吧。这里放一个&lt;a href=&#34;https://androidfilehost.com/?fid=2188818919693768129&#34;&gt;可信的文件源&lt;/a&gt;，使用一切正常&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;PE官方提供的recovery镜像无法刷入Pixel Experience固件，手机端返回的错误码为&lt;code&gt;error in /sideload/package.zip (status 1)&lt;/code&gt;&lt;/p&gt;
&lt;p&gt; 这个原因我也无从得知了，在xda上草草看了一眼就改用&lt;a href=&#34;https://twrp.me/&#34;&gt;twrp recovery&lt;/a&gt;进行刷入了，一切正常。虽然在PE官网的固件changelog中是提到用PE的recovery进行刷入^.^&lt;/p&gt;
 &lt;img src=&#34;https://s2.loli.net/2022/01/08/GExi9ohSjsAQROP.png&#34; alt=&#34;Use PE recovery to flash the build.&#34;&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;最后一个问题纯粹是自己手贱了属于，不要回锁bootloader！&lt;/p&gt;
&lt;p&gt; 官方教程&lt;a href=&#34;https://wiki.pixelexperience.org/devices/kebab/install/#post-install-instructions&#34;&gt;Post-install instructions&lt;/a&gt;中提到了刷入 &lt;code&gt;avb_custom_key&lt;/code&gt;后可回锁，切记切记要确认成功刷入后再回锁！昨天avb_custom_key下载失败，得到的只是一个空文件，我没有查看是否成功刷入直接进行了回锁，结果自然是一个鲜艳的红色感叹号，和那句令人窒息的&amp;quot;your device is corrupt. It can&amp;#39;t be trusted and will not boot&amp;quot;&lt;/p&gt;
&lt;p&gt; 如果真的像我一样手贱回锁了，先别急，我昨天一通操作，居然进入了fastboot模式，然后又直接解锁了。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;步骤如下:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;power&lt;/code&gt;+&lt;code&gt;volume up&lt;/code&gt;彻底关机&lt;/li&gt;
&lt;li&gt;&lt;code&gt;volume down&lt;/code&gt;+&lt;code&gt;volume up&lt;/code&gt;，再插入数据线，就进入fastboot模式了&lt;/li&gt;
&lt;/ol&gt;
&lt;/blockquote&gt;
&lt;p&gt; 这只是昨天乱尝试偶然获得的一个解决方法。如果如上操作未能顺利进入fastboot模式，建议还是稳妥起见高通9008刷机为好。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;shi-yong-zhong-de-wen-ti&#34;&gt;使用中的问题&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;通话录音&lt;/p&gt;
&lt;p&gt; 原生安卓据说是要开始支持这一项了，不过这次刷入的PE Plus还没有这一功能，借助magisk模块&lt;a href=&#34;https://callrecorder.skvalex.com/get&#34;&gt;Call Recorder - SKVALEX&lt;/a&gt;可以很好地解决这一问题。相似的解决方案也很多，不做赘述&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;短信拦截&lt;/p&gt;
&lt;p&gt; 这是原生安卓最大的痛点了，目前还没有太好的解决方法，待定…&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;取消Google Play对特定应用的更新提醒&lt;/p&gt;
&lt;p&gt; Google Play一个我不太接受的特性就是不能忽略应用更新了。magisk的模块库中的&lt;a href=&#34;https://github.com/Magisk-Modules-Repo/Detach&#34;&gt;Detach&lt;/a&gt;能够很好的满足这一要求。使用及操作要求在官方github仓库中有很清晰的介绍，不做赘述。需要注意的一点是，magisk安装Detach需要另一模块Busybox for Android NDK作基础，这一模块在magisk模块库中直接下载安装即可。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;应用列表隐藏&lt;/p&gt;
&lt;p&gt; 也是刷机玩家的老朋友了，主要是为了避免应用读取已安装应用列表从而生成用户画像，一定程度上也是隐私保护的一种方式。&lt;/p&gt;
&lt;p&gt; 源仓库地址：&lt;a href=&#34;https://github.com/Dr-TSNG/Hide-My-Applist&#34;&gt;github&lt;/a&gt;，这项功能要从LSPosed中安装，按照要求一步步下载apk安装，并从软件中安装需要的magisk模块，设定白&amp;#x2F;黑名单并将规则作用于应用即可。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;更方便的联网控制&lt;/p&gt;
&lt;p&gt; 相比于安卓自带的联网控制需要一个一个软件地进行管理，利用&lt;a href=&#34;https://github.com/ukanth/afwall/&#34;&gt;AFWall+&lt;/a&gt;进行联网控制就容易且清晰得多了。这是一个可以从Google Play直接获取的应用。使用也非常直观，勾选想要限制的联网功能（局域网、WiFi、移动数据），再点击右上角应用规则即可。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;不知道什么原因，ipv6总是隔一段时间就掉线，重启路由器后又恢复正常。又因为个人有pt做种需求，ipv6又是不可或缺的条件，所以写个简单的脚本，当ipv6又断线时自动重启路由器&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;ipv6 check script, reboot &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;url=&amp;lt;an ipv6-only site&amp;gt;  || delete the &lt;span class=&#34;string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt; to take effect or replace &lt;span class=&#34;string&#34;&gt;&amp;#x27;$url&amp;#x27;&lt;/span&gt; with actual url down &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; the corresponding &lt;span class=&#34;built_in&#34;&gt;command&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;timeout=1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;check BEGIN&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ping -c $n -W $timeout $url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ $? != 0 ];then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;failed, try reboot&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reboot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;working fine!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;脚本内容一目了然，需要注意的一点，&lt;code&gt;logger -t&lt;/code&gt;在log中写入信息时需要两个字符串作为输入，如上文的语句运行后在padavan管理面板的log显示如下：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:00 [ipv6]:  check BEGIN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:03 [ipv6]:  working fine&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;实际使用中，这样可能会导致log栏中的内容被以上两条占满，可以在测试实际自动运行正常后将log栏输出删除。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;cao-zuo-guo-cheng&#34;&gt;操作过程&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;勾选高级设置-系统管理-服务-启用ssh服务，windows可能会因为端口原因无法连接，打开对应端口即可&lt;/p&gt;
 &lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ssh admin@192.168.123.1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;没有修改默认管理地址的话padavan的地址就是192.168.123.1，账号密码根据个人设置对应输入&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;进入路由器后，要先找到&lt;code&gt;/etc/storage/&lt;/code&gt;路径，因为其余路径在路由器重启后会自动恢复。脚本还要重复用呢是吧~&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;直接用&lt;code&gt;vi ipv6_check.sh&lt;/code&gt;命令新建脚本，将上面的内容输入保存退出即可。提醒一下vi的操作最好先熟悉熟悉。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;由于padavan系统的设置，如果没有执行保存脚本，就并没有真正的写入路由器Rom里，重启之后文件还会丢失。&lt;br&gt; 执行&lt;code&gt;/sbin/mtd_storage.sh save&lt;/code&gt;保存配置。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;设置定时脚本&lt;br&gt; 系统管理-服务-Cron守护程序（计划任务）-Crontab中输入&lt;code&gt;*/10 * * * * /etc/storage/ipv6_check.sh&lt;/code&gt;，设置每十分钟运行一次脚本，大功告成！&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;blockquote&gt;
&lt;p&gt;假期有点无聊，搞个密码管理器，做个记录&lt;br&gt;Here: &lt;a href=&#34;https://github.com/Mocky-533/PasswordBox&#34;&gt;&lt;strong&gt;repository link&lt;/strong&gt;&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2&gt;&lt;span id=&#34;jian-jie&#34;&gt;简介&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;头脑一热做的一个小项目，要实现的功能大致如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;登陆口令（称为口令，防止与后面的“密码”混淆）验证&lt;/li&gt;
&lt;li&gt;添加密码条目&lt;ul&gt;
&lt;li&gt;app&amp;#x2F;站点名称&lt;/li&gt;
&lt;li&gt;账号&amp;#x2F;邮箱&lt;/li&gt;
&lt;li&gt;密码&lt;/li&gt;
&lt;li&gt;添加时间（程序自动生成）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;密码加密&lt;/li&gt;
&lt;li&gt;密码条目存储&lt;/li&gt;
&lt;li&gt;密码条目查询&lt;ul&gt;
&lt;li&gt;按app&amp;#x2F;站点名称&lt;/li&gt;
&lt;li&gt;按账号&amp;#x2F;邮箱&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;更新&amp;#x2F;删除存储的密码条目&lt;ul&gt;
&lt;li&gt;先获取密码条目在数据库中的ID作为参数——&lt;del&gt;偷懒行为&lt;/del&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;修改登陆口令&lt;/li&gt;
&lt;li&gt;(2022.1)新增密码生成，获取用户输入的密码长度数值，随机生成包括大小写字母、数字、符号的乱码作为强密码&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;del&gt;交互的话先弄成命令行程序&lt;/del&gt; 已改用curses库实现&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;ge-gong-neng-jian-jie&#34;&gt;各功能简介&lt;/span&gt;&lt;/h2&gt;&lt;h3&gt;&lt;span id=&#34;deng-lu-kou-ling-she-zhi-yan-zheng-ji-xiu-gai&#34;&gt;登陆口令设置、验证及修改&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;实现方法很简单了：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;第一次启动程序要求设置一个登陆口令，重复输入检查无误后，hash加密，存储到数据库里。之后登陆对输入的密码进行校验即可。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;设置登陆口令以及后续使用时输入口令需要对输入内容进行隐藏&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;p&gt;用getpass库：&lt;/p&gt;
 &lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; getpass&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pwd = getpass.getpass(&lt;span class=&#34;string&#34;&gt;&amp;quot;[PASSWROD]: &amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;# hide input&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;改用curses库后直接用curses.noecho()实现即可&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;python-curses-ku-shi-yong&#34;&gt;python curses库使用&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;不开坑，不填坑，&lt;a href=&#34;https://docs.python.org/3/library/curses.html&#34;&gt;官方DOC&lt;/a&gt;放在这算了，都是很简单的操作&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;mi-ma-jia-jie-mi-mi-ma-tiao-mu-zeng-shan-geng-xin-ji-cha-xun&#34;&gt;密码加解密，密码条目增删、更新及查询&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;由于hash加密的不可逆性，这里无法使用，因为后面还要查询密码并显示，所以需要寻找一种可逆的加密方法。偷个懒，直接平移ASCII码，偏移量选为&lt;em&gt;当前时间的秒数+15&lt;/em&gt;，模拟一个随机加密。自然解密就是反向平移。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# offset functions。 only one is enough actually, with changing offset value&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;enascii&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;num: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; num - offset &amp;gt;= &lt;span class=&#34;number&#34;&gt;33&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;93&lt;/span&gt; + num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;deascii&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;num: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; num + offset &amp;lt;= &lt;span class=&#34;number&#34;&gt;126&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; num + offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; num + offset - &lt;span class=&#34;number&#34;&gt;93&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# encryption&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;encrypt&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;psw: &lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypt_num = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; psw:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        encrypt_num.append(enascii(&lt;span class=&#34;built_in&#34;&gt;ord&lt;/span&gt;(i), offset + &lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypted = [&lt;span class=&#34;built_in&#34;&gt;chr&lt;/span&gt;(a) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; encrypt_num]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(encrypted)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# decryption, s as encrypted password string&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;decrypt&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;s: &lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    pwd = [&lt;span class=&#34;built_in&#34;&gt;chr&lt;/span&gt;(deascii(&lt;span class=&#34;built_in&#34;&gt;ord&lt;/span&gt;(a), offset + &lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;)) &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; s]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(pwd)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;添加和更新密码时的密码输入没有隐藏，也算是偷个懒吧，毕竟有些比较复杂的密码输错了要重新输两遍甚至多遍难免会烦。&lt;/p&gt;
&lt;p&gt;添加密码时，在输入站点和账户后对数据库中已有条目进行查询，若发现有同站点同账户密码条目询问是否停止添加转而更新密码。这里匹配方式为：站点信息完全相同，账户信息不区分大小。&lt;/p&gt;
&lt;p&gt;sqlite3进行正则搜索遇到了点困难，翻了好久文档也没弄出个方法，最后选择基于&lt;a href=&#34;https://stackoverflow.com/questions/5365451/problem-with-regexp-python-and-sqlite&#34;&gt;StackOverflow中的一个方法&lt;/a&gt;完成。密码条目查询正则匹配设置大小写不敏感，即将上述解法中正则表达式定义改为：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;reg = re.&lt;span class=&#34;built_in&#34;&gt;compile&lt;/span&gt;(expr, re.I)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;其余的内容就是数据库的操作了，放在这当备用吧&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; sqlite3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db = sqlite3.connect(&lt;span class=&#34;string&#34;&gt;&amp;quot;database.db&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cur = db.cursor()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cur.execute() &lt;span class=&#34;comment&#34;&gt;# commands here&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result1 = cur.fetchall()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result2 = cur.fetchone()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.commit()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create_command = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;CREATE TABLE (table) ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;add_command = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;INSERT INTO (table) (cols) VALUES (value)&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# value must be tuple type&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;select_command = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;SELECT * FROM (table) WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;update_command = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;UPDATE (table) SET ... WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;delete_command = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;DELETE FROM (table) WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2&gt;&lt;span id=&#34;to-do&#34;&gt;To Do&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;上面提到了一部分，随时想起什么再写上放这里，&lt;del&gt;咕咕咕&lt;/del&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;GUI&lt;/del&gt; 改用curses库了&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;搜索功能使用正则匹配&lt;/del&gt;已完成&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;重复密码条目添加时进行提示与引导&lt;/del&gt;&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;又想起来一个，curses库只能在限定面板内显示查询结果，这样在对账号（邮箱）进行查询时，由于查询结果很多，可能由于终端面积不足而导致curses库运行出错&lt;/del&gt;  用curses pad解决了&lt;/li&gt;
&lt;/ul&gt;
